"use strict";(globalThis.webpackChunkporto=globalThis.webpackChunkporto||[]).push([[7951],{3758(e){e.exports=JSON.parse('{"version":{"pluginId":"ai","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"aiSidebar":[{"type":"link","href":"/ai/Intro","label":"Introduction","docId":"Intro","unlisted":false},{"type":"link","href":"/ai/Manifesto","label":"Manifesto","docId":"Manifesto","unlisted":false},{"type":"link","href":"/ai/Early Access","label":"Early Access","docId":"Early Access","unlisted":false}]},"docs":{"Early Access":{"id":"Early Access","title":"Early Access","description":"Porto AI is in private testing. The architecture is complete and in use, but it is not published openly yet. Access is shared directly, one team at a time.","sidebar":"aiSidebar"},"Intro":{"id":"Intro","title":"Porto AI","description":"An edition of the Porto architecture designed for codebases that AI agents write, maintain, and evolve, not humans. Same core idea as Porto, self-contained reusable units, but the structure is shaped for how agents read and edit code: fewer files, less indirection, token-efficient layouts, and machine-readable definitions instead of prose.","sidebar":"aiSidebar"},"Manifesto":{"id":"Manifesto","title":"Manifesto","description":"Most code is now written by agents, and that share only grows. A codebase optimized for a human reader is the wrong shape for the reader that actually writes it. Porto AI is built on the opposite premise: design the architecture for the agent first, and let humans steer.","sidebar":"aiSidebar"}}}}')}}]);